import React from "react";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Layout({ children }) {
  return (
    <>
      <Navbar />
      {/* Banner tagline */}
      <div style={{
        backgroundColor: "#004080",
        color: "white",
        textAlign: "center",
        padding: "8px",
        fontStyle: "italic"
      }}>
        Motif‑driven healing for communities
      </div>
      <main>{children}</main>
      <Footer />
    </>
  );
}

export default Layout;
